INSERT OR IGNORE INTO answers (title, options, answer) VALUES ('民主的评价标准是单一的，只有“一人一票”竞选才是民主。', 'A. 对 B. 错', 'B. 错');
INSERT OR IGNORE INTO answers (title, options, answer) VALUES ('坚持党对人民军队的绝对领导，是马克思主义建党建军的一条基本原则。', 'A. 对 B. 错', 'A. 对');
