INSERT OR IGNORE INTO answers (title, options, answer) VALUES ('中国特色社会主义是历史和人民的选择，这一论断的依据包括（ ）。', 'A. 它是在改革开放40多年的伟大实践中走出来的 B. 它是在中华人民共和国成立70多年的持续探索中走出来的 C. 它是在对近代以来180多年中华民族发展历程的深刻总结中走出来的 D. 它是在对中华民族5000多年悠久文明的传承中走出来的', 'A、B、C、D');
INSERT OR IGNORE INTO answers (title, options, answer) VALUES ('（ ）是我们解决台湾问题的最大底气。', 'A. 中国特色社会主义事业取得的伟大成就 B. 我国经济、科技、国防实力的持续增强 C. 包括台湾人民在内的全国各族人民万众一心、同仇敌忾 D. 国际社会支持', 'ABC');
INSERT OR IGNORE INTO answers (title, options, answer) VALUES ('到2035年，基本实现国防和军队现代化，这一步的关键是实现（ ）。', 'A. 军事理论现代化 B. 军队组织形态现代化 C. 军事人员现代化 D. 武器装备现代化', 'A. 军事理论现代化');
INSERT OR IGNORE INTO answers (title, options, answer) VALUES ('人民代表大会制度是坚持（ ）有机统一的根本政治制度安排。', 'A. 党的领导 B. 全面深化改革 C. 人民当家作主 D. 依法治国', 'A、C、D');
INSERT OR IGNORE INTO answers (title, options, answer) VALUES ('习近平总书记指出:“当代中国共产党人和中国人民应该而且一定能够担负起新的文化使命，在实践创造中进行文化创造，在历史进步中实现文化进步!”新时代新的文化使命是（ ）。', 'A. 在新的起点上继续推动文化繁荣 B. 建设文化强国 C. 建设中华民族现代文明 D. 传承发展中华传统文化', 'A. 在新的起点上继续推动文化繁荣');
INSERT OR IGNORE INTO answers (title, options, answer) VALUES ('民生工作离老百姓最近，同老百姓生活最密切，（ ）是我们的第一要务。', 'A. 解决发展问题 B. 解决贫困问题 C. 改善民生 D. 改善生活', 'C. 改善民生');
INSERT OR IGNORE INTO answers (title, options, answer) VALUES ('党的二十大报告指出，中国共产党立志于中华民族千秋伟业，致力于人类和平与发展崇高事业，全党同志要始终牢记“三个务必”，这“三个务必”是（ ）。', 'A. 务必不忘初心、牢记使命 B. 务必谦虚谨慎、艰苦奋斗 C. 务必贯彻好群众路线 D. 务必敢于斗争、善于斗争', 'A. 务必不忘初心、牢记使命  
B. 务必谦虚谨慎、艰苦奋斗  
D. 务必敢于斗争、善于斗争');
INSERT OR IGNORE INTO answers (title, options, answer) VALUES ('坚持马克思主义在意识形态领域指导地位的根本制度，是（ ）的必然要求。', 'A. 高质量发展 B. 坚持和巩固我国社会主义制度 C. 保证我国文化建设正确方向 D. 全面依法治国', 'B. 坚持和巩固我国社会主义制度');
INSERT OR IGNORE INTO answers (title, options, answer) VALUES ('习近平新时代中国特色社会主义思想创立的时代背景是（ ）。', 'A. 世界百年未有之大变局加速演进 B. 新时代中国正处于中华民族伟大复兴的关键时期 C. 我国经济高速度发展 D. 中国成为世界领导角色', 'AB');
INSERT OR IGNORE INTO answers (title, options, answer) VALUES ('推动高质量发展具有的重大战略意义包括（ ）。', 'A. 为全面建设社会主义现代化国家提供更为坚实的物质基础 B. 是不断满足人民对美好生活需要的重要保证 C. 是维护国家长治久安的必然要求 D. 是我国经济发展必须追求的唯一目标', 'ABC');
INSERT OR IGNORE INTO answers (title, options, answer) VALUES ('维护党中央权威和集中统一领导，最关键的是坚决维护（ ）。', 'A. 人民群众的核心地位 B. 习近平同志党中央的核心 C. 行政机关的核心地位 D. 习近平同志全党的核心地位', 'BD');
INSERT OR IGNORE INTO answers (title, options, answer) VALUES ('加快建设教育强国、科技强国、人才强国，坚持（ ）。', 'A. 教育是全面建设社会主义现代化国家的坚实基础 B. 科技是全面建设社会主义现代化国家的强大动力 C. 人才是全面建设社会主义现代化国家的有力支撑 D. 科技是全面建设社会主义现代化国家的坚实基础', 'ABC');
INSERT OR IGNORE INTO answers (title, options, answer) VALUES ('确保党始终总揽全局、协调各方，必须增强政治意识（ ），自觉维护党中央权威和集中统一领导，自觉在思想上政治上行动上同党中央保持高度一致。', 'A. 大局意识 B. 核心意识 C. 中心意识 D. 看齐意识', 'ABD');
INSERT OR IGNORE INTO answers (title, options, answer) VALUES ('建设社会主义文化强国、推动社会主义文化繁荣兴盛，关键在于（ ）。', 'A. 坚定中国特色社会主义文化自信 B. 高质量发展 C. 提高综合国力 D. 贯彻新发展理念', 'A. 坚定中国特色社会主义文化自信');
INSERT OR IGNORE INTO answers (title, options, answer) VALUES ('党的十九届四中全会第一次从（ ）、分配制度、资源配置方式等方面阐述了我国基本经济制度的内涵，把我们党对社会主义基本经济制度的认识提高到一个新境界。', 'A. 经济特点 B. 发展模式 C. 所有制结构 D. 生产力水平', 'C. 所有制结构');
INSERT OR IGNORE INTO answers (title, options, answer) VALUES ('（ ）就是形成以保障基本生活为主的社会公平保障体系，织牢民生安全网的“网底”，对困难群众实行应保尽保。', 'A. 坚守底线 B. 突出重点 C. 完善制度 D. 引导预期', 'A. 坚守底线');
INSERT OR IGNORE INTO answers (title, options, answer) VALUES ('邓小平指出:“社会主义最大的优越性就是（ ），这是体现社会主义本质的一个东西。”', 'A. 党的领导 B. 共同富裕 C. 办事效率高 D. 走和平发展道路', 'B. 共同富裕');
INSERT OR IGNORE INTO answers (title, options, answer) VALUES ('习近平总书记在党的十八届四中全会第二次全体会议上强调，历史是最好的老师。经验和教训使我们党深刻认识到，（ ）是治国理政不可或缺的重要手段。', 'A. 法治 B. 政策 C. 道德 D. 公正', 'A');
INSERT OR IGNORE INTO answers (title, options, answer) VALUES ('2022年4月，习近平在（ ）上提出全球安全倡议。', 'A. 博鳌亚洲论坛年会 B. 世界经济论坛年会 C. 金砖国家领导人峰会 D. “二十国”集团峰会', 'A. 博鳌亚洲论坛年会');
INSERT OR IGNORE INTO answers (title, options, answer) VALUES ('全面依法治国必须抓住领导干部这个（ ）。', 'A. “关键少数” B. “关键力量” C. “关键核心” D. “关键主体”', 'A. “关键少数”');
INSERT OR IGNORE INTO answers (title, options, answer) VALUES ('维护意识形态安全，最主要是（ ）。', 'A. 落实意识形态工作责任制 B. 把意识形态工作的领导权、管理权、话语权牢牢掌握在党的手中 C. 及时掌握意识形态形势和动态 D. 坚持和巩固马克思主义在意识形态领域的指导地位', 'D');
INSERT OR IGNORE INTO answers (title, options, answer) VALUES ('（ ）是我们党的生命线和根本工作路线，是我们党永葆青春活力和战斗力的重要传家宝。', 'A. 武装斗争 B. 群众路线 C. 统一战线 D. 党的领导', 'B. 群众路线');
INSERT OR IGNORE INTO answers (title, options, answer) VALUES ('（ ）是意识形态工作的主阵地、主战场、最前沿。', 'A. 互联网 B. 学校 C. 新闻出版 D. 传统媒体', 'A. 互联网');
INSERT OR IGNORE INTO answers (title, options, answer) VALUES ('新时代中国共产党深刻把握推进共同富裕规律，提出“要深入研究不同阶段的目标，分阶段促进共同富裕：到（ ），全体人民共同富裕取得更为明显的实质性进展，基本公共服务实现均等化”。', 'A. 中国共产党成立一百年 B. “十四五”末 C. 2035年 D. 本世纪中叶', 'C. 2035年');
INSERT OR IGNORE INTO answers (title, options, answer) VALUES ('新时代坚持和发展中国特色社会主义的根本立场是（ ）。', 'A. 坚持党的领导 B. 坚持以人民为中心 C. 坚持全面深化改革 D. 坚持新发展理念', 'B. 坚持以人民为中心');
INSERT OR IGNORE INTO answers (title, options, answer) VALUES ('经济社会发展和国家现代化的基本规律是（ ）。', 'A. 创新驱动发展 B. 科技自立自强 C. 人才引领驱动 D. 教育优先发展', 'A');
INSERT OR IGNORE INTO answers (title, options, answer) VALUES ('建设中国特色社会主义法治体系，必须坚持立法先行，抓住提高（ ）这个关键。', 'A. 立法规则 B. 立法数量 C. 立法原则 D. 立法质量', 'D. 立法质量');
INSERT OR IGNORE INTO answers (title, options, answer) VALUES ('坚持以人民为中心的发展思想，在高质量发展中促进共同富裕，正确处理（ ）的关系，构建初次分配、再分配、三次分配协调配套的基础性制度安排。', 'A. 效率和公平 B. 收入和分配 C. 经济和社会 D. 政府和市场', 'A. 效率和公平');
INSERT OR IGNORE INTO answers (title, options, answer) VALUES ('全面深化改革要坚持（ ）是解放和发展社会生产力、解放和增强社会活力的总开关。', 'A. 实事求是 B. 解放思想 C. 开拓创新 D. 贯彻新发展理念', 'B. 解放思想');
INSERT OR IGNORE INTO answers (title, options, answer) VALUES ('（ ）是社会文明进步的基础，是民族昌盛和国家富强的重要标志，是促进人的全面发展的必然要求。', 'A. 改善民生 B. 社会保障体系 C. 人民健康 D. 就业', 'C. 人民健康');
INSERT OR IGNORE INTO answers (title, options, answer) VALUES ('要坚定维护以（ ）为核心的国际体系、以国际法为基础的国际秩序，维护和巩固第二次世界大战胜利成果，积极维护开放型世界经济体制，加强国际社会应对全球性挑战的能力。', 'A. 本国 B. 联合国 C. 西方发达国家 D. 发展中国家', 'B. 联合国');
INSERT OR IGNORE INTO answers (title, options, answer) VALUES ('我们党的最大政治优势是（ ）。', 'A. 党领导一切 B. 走中国特色社会主义道路 C. 人多力量大 D. 密切联系群众', 'D. 密切联系群众');
INSERT OR IGNORE INTO answers (title, options, answer) VALUES ('新时代党的组织路线强调，以（ ）为重点，着力培养忠诚干净担当的高素质干部。', 'A. 组织体系建设 B. 干部队伍建设 C. 人才队伍建设 D. 党员队伍建设', 'A. 组织体系建设');
INSERT OR IGNORE INTO answers (title, options, answer) VALUES ('党的十八届三中全会作出了全面深化改革的决定，把（ ）确定为全面深化改革的总目标。', 'A. 完善和发展中国特色社会主义制度、推进国家治理体系和治理能力现代化 B. 完善和发展科学执政和民主执政水平、推进国家治理体系现代化 C. 完善和发展依法执政和民主执政水平、推进国家治理能力现代化 D. 完善和发展中国特色社会主义理论、推进国家治理能力现代化', 'A. 完善和发展中国特色社会主义制度、推进国家治理体系和治理能力现代化');
INSERT OR IGNORE INTO answers (title, options, answer) VALUES ('我国国家制度和国家治理体系具有多方面的显著优势，其中最大优势是（ ）。', 'A. 全国一盘棋 B. 人民当家作主 C. 中国共产党领导 D. 以人民为中心', 'C');
INSERT OR IGNORE INTO answers (title, options, answer) VALUES ('社会主要矛盾的变化要求我们必须坚持以（ ）为中心的发展思想。', 'A. 经济建设 B. 人民 C. 科技创新 D. 生态保护', 'B. 人民');
INSERT OR IGNORE INTO answers (title, options, answer) VALUES ('培育和践行社会主义核心价值观，要把（ ）融入社会生活各个方面。', 'A. 社会主义核心价值体系 B. 理想信念、价值理念、道德观念 C. 中华优秀传统文化 D. 社会主义核心价值观', 'D. 社会主义核心价值观');
INSERT OR IGNORE INTO answers (title, options, answer) VALUES ('（ ）是统一战线最核心、最根本的问题。', 'A. 大团结大联合 B. 广交朋友 C. 凝聚人心 D. 坚持党的领导', 'D. 坚持党的领导');
INSERT OR IGNORE INTO answers (title, options, answer) VALUES ('（ ）是我国的根本政治制度，是符合我国国情和实际、体现社会主义国家性质、保证人民当家作主、保障实现中华民族伟大复兴的好制度，是我们党领导人民在人类政治制度史上的伟大创造。', 'A. 区域自治制度 B. 民主集中制 C. 人民代表大会制度 D. 政治协商制度', 'C. 人民代表大会制度');
INSERT OR IGNORE INTO answers (title, options, answer) VALUES ('坚持以人民为中心，在推动社会全面进步中促进（ ）全面发展。', 'A. 人 B. 经济 C. 政治 D. 文化', 'A. 人');
INSERT OR IGNORE INTO answers (title, options, answer) VALUES ('习近平强调在坚持“第一个结合”的基础上，明确提出“第二个结合”就是把马克思主义基本原理同（ ）相结合。', 'A. 人才培养 B. 科技创新 C. 中华优秀传统文化 D. 对外开放', 'C. 中华优秀传统文化');
INSERT OR IGNORE INTO answers (title, options, answer) VALUES ('（ ）是新时代坚持和发展中国特色社会主义的政治保证。', 'A. 全面深化改革开放 B. 坚持中国共产党领导 C. 坚持以人民为中心 D. 坚定不移全面从严治党', 'B');
INSERT OR IGNORE INTO answers (title, options, answer) VALUES ('新时代坚持和发展中国特色社会主义的根本动力是（ ）。', 'A. 全面深化对外开放 B. 全面深化改革 C. 全面深化经济体制改革 D. 全面深化政治体制改革', 'B. 全面深化改革');
INSERT OR IGNORE INTO answers (title, options, answer) VALUES ('国家安全工作，归根结底是保障（ ），为群众安居乐业提供坚强保障。有了安全感，获得感才有保障，幸福感才会持久。', 'A. 人民利益 B. 社会稳定 C. 经济发展 D. 领土完整', 'A. 人民利益');
INSERT OR IGNORE INTO answers (title, options, answer) VALUES ('（ ）明确提出形成中国特色社会主义法律体系的重大任务。', 'A. 党的十五大 B. 党的十八大 C. 党的十九届六中全会 D. 党的二十大', 'A. 党的十五大');
INSERT OR IGNORE INTO answers (title, options, answer) VALUES ('引领全球治理体系改革应坚持的理念是（ ）。', 'A. 人权 B. 维护国家核心利益 C. 公平正义 D. 开放有序', 'C. 公平正义');
INSERT OR IGNORE INTO answers (title, options, answer) VALUES ('（ ），是检验更高水平的平安中国建设成效的重要标志。', 'A. 人民生活水平提升 B. 社会治理能力现代化 C. 社会更加安全稳定有序 D. 共同富裕', 'C. 社会更加安全稳定有序');
INSERT OR IGNORE INTO answers (title, options, answer) VALUES ('（ ），习近平在第七十六届联合国大会上提出全球发展倡议。', 'A. 2019年8月 B. 2020年7月 C. 2021年9月 D. 2022年6月', 'C. 2021年9月');
INSERT OR IGNORE INTO answers (title, options, answer) VALUES ('坚持人才强军，必须（ ）。', 'A. 实施新时代人才强军战略，锻造德才兼备的高素质、专业化新型军事人才 B. 培养有灵魂、有本事、有血性、有品德的新时代革命军人 C. 锻造具有铁一般信仰、铁一般信念、铁一般纪律、铁一般担当的过硬部队 D. 按照法治要求转变治军方式，实现从单纯依靠行政命令的做法向依法行政的根本性转变', 'A');
INSERT OR IGNORE INTO answers (title, options, answer) VALUES ('总体国家安全观以（ ）为基础，加强经济安全风险预警、防控机制和能力建设。', 'A. 国土安全 B. 经济安全 C. 国内安全 D. 国际安全', 'B. 经济安全');
INSERT OR IGNORE INTO answers (title, options, answer) VALUES ('面对波谲云诡的国际形势、复杂敏感的周边环境、艰巨繁重的改革发展稳定任务，我们必须树立（ ）。', 'A. 忧患意识 B. 零和思维 C. 底线思维 D. 全局意识', 'A. 忧患意识');
INSERT OR IGNORE INTO answers (title, options, answer) VALUES ('习近平新时代中国特色社会主义思想的内在精神特质是（ ）。', 'A. 人民至上 B. 自信自立 C. 守正创新 D. 问题导向', 'C');
INSERT OR IGNORE INTO answers (title, options, answer) VALUES ('全面依法治国的总抓手是（ ）。', 'A. 建设中国特色社会主义法治体系，建设社会主义法治国家 B. 建设中国特色社会主义法治体系 C. 建设社会主义法治国家 D. 坚持中国共产党的领导', 'B. 建设中国特色社会主义法治体系');
INSERT OR IGNORE INTO answers (title, options, answer) VALUES ('习近平强军思想明确（ ）是人民军队建军之本、强军之魂。', 'A. 政治工作 B. 党对人民军队的绝对领导 C. 练兵备战 D. 先进科技', 'B. 党对人民军队的绝对领导');
INSERT OR IGNORE INTO answers (title, options, answer) VALUES ('在网络统战工作方面，要把（ ）结合起来，走好网络群众路线，支持网络人士为维护意识形态安全发挥正能量。', 'A. “面对面”和“键对键” B. “面对面”和“线对线” C. “网对网”和“线对线” D. “键对键”和“线对线”', 'A. “面对面”和“键对键”');
INSERT OR IGNORE INTO answers (title, options, answer) VALUES ('（ ）是全面建设社会主义现代化国家的强大动力', 'A. 科技 B. 教育 C. 人才 D. 创新', 'D. 创新');
INSERT OR IGNORE INTO answers (title, options, answer) VALUES ('（ ），这是实现祖国统一的战略思路。', 'A. 坚持“和平统一、一国两制”基本方针 B. 坚持一个中国原则和“九二共识” C. 坚持推动两岸关系融合发展 D. 坚持在祖国大陆发展进步基础上解决台湾问题', 'A. 坚持“和平统一、一国两制”基本方针');
INSERT OR IGNORE INTO answers (title, options, answer) VALUES ('我们坚决反对任何国家以任何借口干涉（ ）事务，这是国际社会公认的准则。', 'A. 香港、澳门和台湾 B. 周边国家 C. 欧洲国家 D. 美洲国家', 'A');
INSERT OR IGNORE INTO answers (title, options, answer) VALUES ('一体推进“三不腐”机制中，“不想腐”的关键是（ ）。', 'A. 强化不敢腐的震慑 B. 扎牢不能腐的笼子 C. 增强不想腐的自觉 D. 加强不能腐的制度', 'C. 增强不想腐的自觉');
INSERT OR IGNORE INTO answers (title, options, answer) VALUES ('“一国两制”的根本宗旨是（ ）。', 'A. 保持香港、澳门长期繁荣稳定 B. 解决台湾问题 C. 维护国家主权、安全、发展利益，保持香港、澳门长期繁荣稳定 D. 实现中华民族伟大复兴', 'C. 维护国家主权、安全、发展利益，保持香港、澳门长期繁荣稳定');
INSERT OR IGNORE INTO answers (title, options, answer) VALUES ('习近平在（ ）报告中进一步强调“打铁必须自身硬”，充分表明我们党坚持刀刃向内的非凡勇气和高度清醒。', 'A. 党的十八届三中全会 B. 党的十九大 C. 党的十九届六中全会 D. 党的二十大', 'B. 党的十九大');
INSERT OR IGNORE INTO answers (title, options, answer) VALUES ('全面从严治党必须把（ ）挺在前面，纪严于法、纪在法前，这是全面从严治党的治本之策。', 'A. 纪律 B. 法律 C. 道德 D. 制度', 'A. 纪律');
INSERT OR IGNORE INTO answers (title, options, answer) VALUES ('习近平总书记指出，中国特色社会主义是社会主义，不是别的什么主义。这一论断的核心依据是中国特色社会主义坚持了（ ）。', 'A. 资本主义市场经济体制 B. 马克思主义关于科学社会主义的基本原则 C. 西方议会民主制度 D. 多党轮流执政模式', 'B. 马克思主义关于科学社会主义的基本原则');
INSERT OR IGNORE INTO answers (title, options, answer) VALUES ('检验我们一切工作的最高标准是（ ）。', 'A. 经济发展水平 B. 综合国力提升 C. 人民拥护不拥护、赞成不赞成、高兴不高兴、答应不答应 D. 社会稳定程度', 'C. 人民拥护不拥护、赞成不赞成、高兴不高兴、答应不答应');
INSERT OR IGNORE INTO answers (title, options, answer) VALUES ('提出构建人类命运共同体重大理念，提出共建“一带一路”倡议，提出全球发展倡议、全球安全倡议、全球文明倡议，深刻回答（ ）的时代课题。', 'A. “共建人类家园” B. “什么是人类命运共同体” C. “人类向何处去” D. “世界怎么了、我们怎么办”', 'D. “世界怎么了、我们怎么办”');
INSERT OR IGNORE INTO answers (title, options, answer) VALUES ('完善和发展中国特色社会主义制度、推进国家治理体系和治理能力现代化。后一句规定了（ ）。', 'A. 在根本方向指引下完善和发展中国特色社会主义制度的鲜明指向 B. 全面深化改革的根本方向 C. 全面深化改革的主要目的 D. 全面深化改革的出发点和落脚点', 'A. 在根本方向指引下完善和发展中国特色社会主义制度的鲜明指向');
INSERT OR IGNORE INTO answers (title, options, answer) VALUES ('（ ）是人民当家作主和依法治国的根本保证。', 'A. 人民民主 B. 党的领导 C. 宪法 D. 全过程民主', 'B. 党的领导');
